write('assets/js/calculators.js',`'use strict';
/*
 * CENTRAL TAX CONFIGURATION — AUTHORITATIVE ANNUAL REVIEW REQUIRED.
 * These values are planning assumptions, not a claim of current IRS approval.
 * reviewedOn records the site content review date, not authoritative validation.
 */
const TAX_CONFIG=Object.freeze({
  label:'Planning assumptions — requires annual verification',
  reviewedOn:'2026-07-12',
  applicableTaxYear:'Requires annual verification before publication use',
  seTaxableShare:0.9235, // Requires annual verification.
  socialSecurityRate:0.124, // Requires annual verification.
  medicareRate:0.029, // Requires annual verification.
  additionalMedicareRate:0.009, // Requires annual verification.
  socialSecurityWageBase:176100, // PLACEHOLDER planning value: requires authoritative tax-year verification.
  additionalMedicareThresholds:{single:200000,mfj:250000,mfs:125000,hoh:200000,qw:200000}, // Requires annual verification.
  employeeFicaRate:0.0765 // Simplified comparison only; requires annual verification and wage-base handling.
});
const money=n=>Number.isFinite(n)?new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(n):'—';
const pct=n=>Number.isFinite(n)?new Intl.NumberFormat('en-US',{style:'percent',maximumFractionDigits:1}).format(n):'—';
const num=(form,id)=>{const el=form.querySelector('#'+id);return el&&el.value.trim()!==''?Number(el.value):0};
const set=(id,value,format=money)=>{const el=document.getElementById(id);if(el)el.textContent=typeof value==='string'?value:format(value)};
function validate(form,required=[]){
  form.querySelectorAll('.field-error').forEach(x=>x.remove());form.querySelectorAll('.has-error').forEach(x=>x.classList.remove('has-error'));
  const errors=[];form.querySelectorAll('input[type=number]').forEach(el=>{const empty=el.value.trim()==='';if((required.includes(el.id)&&empty)||(!empty&&(!Number.isFinite(Number(el.value))||Number(el.value)<0))){errors.push(el);const field=el.closest('.field');field.classList.add('has-error');const msg=document.createElement('p');msg.className='field-error';msg.id=el.id+'Error';msg.textContent=empty?'Enter a value of zero or more.':'Use a valid number of zero or more.';field.append(msg);el.setAttribute('aria-describedby',msg.id);el.setAttribute('aria-invalid','true');}else{el.removeAttribute('aria-invalid');}});
  const summary=form.querySelector('.error-summary');if(errors.length){summary.hidden=false;summary.textContent='Please correct '+errors.length+' highlighted field'+(errors.length===1?'':'s')+'.';summary.focus();return false}summary.hidden=true;return true;
}
function seTax(net,status='single'){
 const taxable=Math.max(0,net)*TAX_CONFIG.seTaxableShare;
 const ss=Math.min(taxable,TAX_CONFIG.socialSecurityWageBase)*TAX_CONFIG.socialSecurityRate;
 const med=taxable*TAX_CONFIG.medicareRate;
 const threshold=TAX_CONFIG.additionalMedicareThresholds[status]??TAX_CONFIG.additionalMedicareThresholds.single;
 const add=Math.max(0,taxable-threshold)*TAX_CONFIG.additionalMedicareRate;
 return{taxable,ss,med,add,total:ss+med+add,deductible:(ss+med)/2};
}
function bind(id,required,calculate){const form=document.getElementById(id);if(!form)return;form.addEventListener('submit',e=>{e.preventDefault();if(validate(form,required))calculate(form)});form.addEventListener('reset',()=>setTimeout(()=>{form.querySelector('.error-summary').hidden=true;form.querySelectorAll('.field-error').forEach(x=>x.remove());document.querySelectorAll('.results strong').forEach(x=>x.textContent='—')},0));}
bind('seCalc',['grossIncome','businessExpenses'],f=>{const net=Math.max(0,num(f,'grossIncome')+num(f,'otherSeIncome')-num(f,'businessExpenses'));const x=seTax(net,f.filingStatus.value);set('netIncome',net);set('taxableSe',x.taxable);set('socialSecurity',x.ss);set('medicare',x.med);set('additionalMedicare',x.add);set('seTax',x.total);set('deductibleHalf',x.deductible);set('federalEstimate',net*num(f,'federalRate')/100)});
bind('quarterlyCalc',['annualSeIncome','businessExpenses','federalRate'],f=>{const net=Math.max(0,num(f,'annualSeIncome')-num(f,'businessExpenses'));const base=Math.max(0,net+num(f,'otherIncome')-num(f,'estimatedDeductions'));const income=base*num(f,'federalRate')/100;const se=seTax(net,f.filingStatus.value).total;const due=Math.max(0,income+se-num(f,'expectedWithholding')-num(f,'estimatedCredits'));set('netBusiness',net);set('incomeTaxBase',base);set('incomeTax',income);set('seTax',se);set('annualDue',due);['q1','q2','q3','q4'].forEach(id=>set(id,due/4))});
bind('takehomeCalc',['grossIncome','businessExpenses','federalRate','stateRate'],f=>{const net=Math.max(0,num(f,'grossIncome')-num(f,'businessExpenses'));const se=seTax(net).total, fed=net*num(f,'federalRate')/100,state=net*num(f,'stateRate')/100;const annual=Math.max(0,net-se-fed-state-num(f,'retirement')-num(f,'healthInsurance'));set('netBusiness',net);set('seTax',se);set('federalTax',fed);set('stateTax',state);set('annualTakeHome',annual);set('monthlyTakeHome',annual/12)});
bind('compareCalc',['contractIncome','w2Salary','businessExpenses'],f=>{const contract=num(f,'contractIncome'),salary=num(f,'w2Salary');let diff=num(f,'payrollDifference');if(!f.payrollDifference.value.trim())diff=Math.max(0,seTax(Math.max(0,contract-num(f,'businessExpenses'))).total-Math.min(salary,TAX_CONFIG.socialSecurityWageBase)*TAX_CONFIG.employeeFicaRate);const c=contract-num(f,'businessExpenses')-num(f,'healthDifference')-diff,w=salary+num(f,'benefitsValue')+num(f,'ptoValue')+num(f,'retirementMatch'),delta=c-w;set('contractNet',c);set('w2Net',w);set('payrollTaxDiff',diff);set('comparison',Math.abs(delta));set('winner',Math.abs(delta)<1?'Approximately equal':delta>0?'1099 package':'W-2 package')});
bind('mileageCalc',['businessMiles','mileageRate'],f=>{const base=num(f,'businessMiles')*num(f,'mileageRate'),m=base+num(f,'parkingTolls'),a=num(f,'actualExpenses')+num(f,'parkingTolls');set('mileageBase',base);set('mileageDeduction',m);set('actualDeduction',a);set('betterMethod',m===a?'Equal entered estimates':m>a?'Mileage method':'Actual-expense method')});
bind('homeOfficeCalc',['officeSqFt','homeSqFt','simplifiedRate','sqFtLimit'],f=>{const office=num(f,'officeSqFt'),home=num(f,'homeSqFt');if(home===0||office>home){const s=f.querySelector('.error-summary');s.hidden=false;s.textContent=home===0?'Total home square footage must be greater than zero.':'Office square footage cannot exceed total home square footage.';s.focus();return}const share=office/home,simple=Math.min(office,num(f,'sqFtLimit'))*num(f,'simplifiedRate'),actual=num(f,'directExpenses')+num(f,'indirectExpenses')*share;set('businessPercentage',share,pct);set('simplified',simple);set('actual',actual);set('largerMethod',simple===actual?'Equal preliminary estimates':simple>actual?'Simplified method':'Actual method')});
bind('quickCalc',['quickIncome','quickExpenses','quickFederalRate','quickStateRate'],f=>{const net=Math.max(0,num(f,'quickIncome')-num(f,'quickExpenses'));const reserve=seTax(net,f.quickStatus.value).total+net*(num(f,'quickFederalRate')+num(f,'quickStateRate'))/100;set('quickTotal',reserve);const note=document.getElementById('quickNet');if(note)note.textContent='From estimated net income of '+money(net)+'. Estimate only.'});
`);

